"use client";

import { useState, useMemo } from "react";
import Link from "next/link";
import { PAGE_ROUTES } from "@/navigation/page.navigation.routes";

// Example menu config by role
const MENU_CONFIG = {
  ADMIN: [
    {
      title: "User Management",
      children: [
        { title: "Admin Users", href: PAGE_ROUTES.ADMIN_PAGES.ADMIN_USERS },
        { title: "Users", href: PAGE_ROUTES.ADMIN_PAGES.USERS },
        { title: "Partners", href: PAGE_ROUTES.ADMIN_PAGES.PARTNERS },
      ],
    },
    {
      title: "Settings",
      children: [
        { title: "Roles", href: PAGE_ROUTES.ADMIN_PAGES.ROLES },
        { title: "Statuses", href: PAGE_ROUTES.ADMIN_PAGES.STATUSES },
      ],
    },
  ],
  PARTNER: [
    {
      title: "Packages",
      children: [
        { title: "My Packages", href: PAGE_ROUTES.PARTNER_PAGES.PACKAGES },
        { title: "Bookings", href: PAGE_ROUTES.PARTNER_PAGES.BOOKINGS },
        { title: "Profile", href: PAGE_ROUTES.PARTNER_PAGES.PROFILE },
      ],
    },
    {
      title: "Bookings",
      children: [
        { title: "My Bookings", href: PAGE_ROUTES.PARTNER_PAGES.BOOKINGS },
      ],
    },
    {
      title: "Profile",
      children: [
        { title: "Edit Profile", href: PAGE_ROUTES.PARTNER_PAGES.PROFILE },
      ],
    },
  ],
  USER: [
    {
      title: "Bookings",
      children: [
        { title: "My Bookings", href: PAGE_ROUTES.USER_PAGES.BOOKINGS },
      ],
    },
    {
      title: "Profile",
      children: [
        { title: "Edit Profile", href: PAGE_ROUTES.USER_PAGES.PROFILE },
      ],
    },
  ],
};

const Sidebar = ({ role }) => {
  const [openMenus, setOpenMenus] = useState({});

  // Memoize menu items for current role
  const menus = useMemo(() => MENU_CONFIG[role] || [], [role]);

  const toggleMenu = (title) => {
    setOpenMenus((prev) => ({ ...prev, [title]: !prev[title] }));
  };

  return (
    <aside className="w-60 min-h-screen bg-white dark:bg-zinc-800 border-r border-zinc-200 dark:border-zinc-700 shadow-md">
      <div className="p-4">
        <h2 className="text-xl font-bold text-zinc-800 dark:text-zinc-100">
          {role}
        </h2>
      </div>

      <nav className="px-4">
        {menus.map((menu) => (
          <div key={menu.title} className="mb-4">
            {/* Parent item */}
            {menu.children?.length > 0 ? (
              <button
                onClick={() => toggleMenu(menu.title)}
                className="w-full text-left font-semibold text-zinc-700 dark:text-zinc-300 hover:text-primary dark:hover:text-indigo-400"
              >
                {menu.title}
              </button>
            ) : (
              <span className="font-semibold">{menu.title}</span>
            )}

            {/* Children */}
            {menu.children && openMenus[menu.title] && (
              <ul className="ml-4 mt-2 space-y-2 text-sm">
                {menu.children.map((item) => (
                  <li key={item.title}>
                    <Link
                      href={item.href}
                      className="block h-5 text-zinc-600 dark:text-zinc-400 flex items-center hover:text-primary dark:hover:text-indigo-400 cursor-pointer hover:bg-primary-light dark:hover:bg-zinc-700 px-2 py-1 rounded"
                    >
                      {item.title}
                    </Link>
                  </li>
                ))}
              </ul>
            )}
          </div>
        ))}
      </nav>
    </aside>
  );
};

export default Sidebar;
